    p = data["parameters"]["p"]
    N = data["parameters"]["N"]
    Tmax = data["parameters"]["Tmax"]
    d0 = data["parameters"]["d0"]
    dr = data["parameters"]["dr"]
    c = data["parameters"]["c"]
    cpos = data["parameters"]["cpos"]
    cneg = data["parameters"]["cneg"]

