        # ---------------------------------------------------------
        # 5. TIME DYNAMICS PLOTS
        # ---------------------------------------------------------
        print("-> Generating Time Dynamics Plots...")

        if RT_mean_time_series.size > 0:
            # Time vector for the steady state
            time_steady = np.arange(TT, Tmax)

            # All time series
            mean_c1 = RT_mean_time_series[TT:, 0]
            std_c1 = RT_std_time_series[TT:, 0]
            mean_c2, std_c2 = np.zeros_like(mean_c1), np.zeros_like(std_c1)
            mean_c3, std_c3 = np.zeros_like(mean_c1), np.zeros_like(std_c1)

            # A.1. Giant Component Evolution (Steady State, All Clusters)
            plt.figure(figsize=(6, 4))
            plt.title(f"Fraction of Active Nodes Over Time\n(Steady State, p={p:.2f})")

            # Cluster 1 (Giant)
            plt.plot(time_steady, mean_c1, label='Cluster 1 (Giant)', color='magenta', linewidth=2)
            # Shaded area for standard deviation (clipped between 0 and 1)
            plt.fill_between(time_steady,
                             np.clip(mean_c1 - std_c1, 0, 1),
                             np.clip(mean_c1 + std_c1, 0, 1),
                             color='magenta', alpha=0.2)

            # Cluster 2
            if RT_mean_time_series.shape[1] > 1:
                mean_c2 = RT_mean_time_series[TT:, 1]
                std_c2 = RT_std_time_series[TT:, 1]
                plt.plot(time_steady, mean_c2, label='Cluster 2', color='green', linewidth=2)
                plt.fill_between(time_steady,
                                 np.clip(mean_c2 - std_c2, 0, 1),
                                 np.clip(mean_c2 + std_c2, 0, 1),
                                 color='green', alpha=0.2)

            # Cluster 3
            if RT_mean_time_series.shape[1] > 2 and plot_third_cluster:
                mean_c3 = RT_mean_time_series[TT:, 2]
                std_c3 = RT_std_time_series[TT:, 2]
                plt.plot(time_steady, mean_c3, label='Cluster 3', color='blue', linewidth=2)
                plt.fill_between(time_steady,
                                 np.clip(mean_c3 - std_c3, 0, 1),
                                 np.clip(mean_c3 + std_c3, 0, 1),
                                 color='blue', alpha=0.2)
            plt.xlabel('Time (iterations)')
            plt.ylabel('Fraction of Active Nodes (R)')
            plt.xlim(TT, Tmax)
            plt.ylim(0, 1.05)
            plt.grid(True, linestyle='--', alpha=0.5)
            plt.legend()
            plt.tight_layout()
            plt.savefig(os.path.join(fig_dir, f"R_evolution_steady_p{p:.2f}.png"), dpi=400)
            plt.close()

            # A.2. Giant Component Evolution (Steady State, Cluster 1, Giant Component)
            plt.figure(figsize=(6, 4))
            plt.title(f"Fraction of Active Nodes Over Time\n(Steady State, p={p:.2f}, Giant Component)")
            plt.plot(time_steady, mean_c1, label='Cluster 1 (Giant)', color='magenta', linewidth=2)
            # Shaded area for standard deviation (clipped between 0 and 1)
            plt.fill_between(time_steady,
                             np.clip(mean_c1 - std_c1, 0, 1),
                             np.clip(mean_c1 + std_c1, 0, 1),
                             color='magenta', alpha=0.2)
            plt.xlabel('Time (iterations)')
            plt.ylabel('Fraction of Active Nodes (R)')
            plt.xlim(TT, Tmax)
            plt.ylim(0, 1.05)
            plt.grid(True, linestyle='--', alpha=0.5)
            plt.tight_layout()
            plt.savefig(os.path.join(fig_dir, f"Cl1_evolution_steady_p{p:.2f}.png"), dpi=400)
            plt.close()

            if RT_mean_time_series.shape[1] > 1:
                # A.3. Giant Component Evolution (Steady State, Cluster 2)
                plt.figure(figsize=(6, 4))
                plt.title(f"Fraction of Active Nodes Over Time\n(Steady State, p={p:.2f}, Cluster 2)")
                plt.plot(time_steady, mean_c2, label='Cluster 2', color='green', linewidth=2)
                plt.fill_between(time_steady,
                                 np.clip(mean_c2 - std_c2, 0, 1),
                                 np.clip(mean_c2 + std_c2, 0, 1),
                                 color='green', alpha=0.2)
                plt.xlabel('Time (iterations)')
                plt.ylabel('Fraction of Active Nodes (R)')
                plt.xlim(TT, Tmax)
                max_y2 = np.max(mean_c2 + std_c2)
                plt.ylim(0, max_y2 * 1.2 if max_y2 > 0 else 0.1)
                plt.grid(True, linestyle='--', alpha=0.5)
                plt.tight_layout()
                plt.savefig(os.path.join(fig_dir, f"Cl2_evolution_steady_p{p:.2f}.png"), dpi=400)
                plt.close()

                # A.4. Comparative Evolution (Cluster 1 vs 2) with Ratio Subplot
                # Figure with 2 subplots vertically stacked, sharing the X axis.
                # height_ratios=[3, 1] means the top plot is 3 times taller than the bottom one.
                fig, (ax1, ax2) = plt.subplots(2, 1, figsize=(6, 5), sharex=True,
                                               gridspec_kw={'height_ratios': [3, 1.2]})

                # --- TOP PANEL: Absolute Sizes ---
                ax1.set_title(f"Cluster 1 & 2 Evolution with Ratio\n(Steady State, p={p:.2f})")

                # Plot Cluster 1 (Giant)
                ax1.plot(time_steady, mean_c1, label='Cluster 1 (Giant)', color='magenta', linewidth=2)
                ax1.fill_between(time_steady,
                                 np.clip(mean_c1 - std_c1, 0, 1),
                                 np.clip(mean_c1 + std_c1, 0, 1),
                                 color='magenta', alpha=0.2)

                # Plot Cluster 2
                ax1.plot(time_steady, mean_c2, label='Cluster 2', color='green', linewidth=2)
                ax1.fill_between(time_steady,
                                 np.clip(mean_c2 - std_c2, 0, 1),
                                 np.clip(mean_c2 + std_c2, 0, 1),
                                 color='green', alpha=0.2)

                ax1.set_ylabel('Fraction of Active Nodes (R)')
                ax1.set_ylim(0, 1.05)
                ax1.grid(True, linestyle='--', alpha=0.5)
                ax1.legend(loc='best')

                # --- BOTTOM PANEL: Ratio C2 / C1 ---
                # Safe division: np.where avoids ZeroDivisionError when mean_c1 is exactly 0
                with np.errstate(divide='ignore', invalid='ignore'):
                    ratio = np.where(mean_c1 > 0, mean_c2 / mean_c1, 0)

                # Plot the ratio as a solid black line to make it look analytical
                ax2.plot(time_steady, ratio, color='black', linewidth=1.5)

                ax2.set_xlabel('Time (iterations)')
                ax2.set_ylabel('Ratio C2/C1')

                # Dynamically adjust the Y-axis of the ratio so it always fits nicely,
                # but has a minimum ceiling of 0.1 to avoid microscopic noise scaling.
                max_ratio = np.nanmax(ratio)
                ax2.set_ylim(0, max(0.1, max_ratio * 1.2))
                ax2.grid(True, linestyle='--', alpha=0.5)

                # Remove the horizontal space between the two panels for a cohesive look
                plt.subplots_adjust(hspace=0.05)

                plt.savefig(os.path.join(fig_dir, f"C1_vs_C2_Ratio_steady_p{p:.2f}.png"), dpi=400)
