                # 3. Add a unified, neutral colorbar for Time
                # We create a dummy Grays scalar mappable so it doesn't favor any specific cluster color
                sm = plt.cm.ScalarMappable(cmap='Greys', norm=plt.Normalize(vmin=0, vmax=Tmax))
