            if nodes_coords_dict[first_seed].shape[1] == 1:
                for seed_name, state_nodes in state_nodes_dict.items():
                    # Skip redundant raster plots for the other seeds
                    if seed_name != seed_list[0]: continue
                    if seed_name not in nodes_coords_dict: continue
                    nodes_coords = nodes_coords_dict[seed_name]

                    seed_fig_dir = os.path.join(folder, seed_name, "figures")
                    os.makedirs(seed_fig_dir, exist_ok=True)  # Just in case

                    plt.figure(figsize=(8, 5))

                    # np.where searches automatically where state_nodes is True
                    # It returns two arrays: one with the time indices and another with the node indices of the active
                    # nodes
                    active_times, active_node_indices = np.where(state_nodes)

                    # We extract the exact spatial position 'y' of those active nodes
                    y_positions = nodes_coords[active_node_indices, 0]

                    # Draw all the points at the same time
                    # s=0.5 makes the points smaller, and alpha=0.8 gives them some transparency to better visualize
                    # overlaps
                    plt.scatter(active_times, y_positions, color='black', s=0.5, alpha=0.8)
                    plt.title(f"Spatiotemporal Evolution (p={p:.2f})")
                    plt.xlabel('Time (iterations)')
