                    os.makedirs(seed_fig_dir, exist_ok=True)  # Just in case

                    plt.figure(figsize=(6, 6))

                    # We create a heatmap based on the frequency of activation of each node
                    activation_freq = np.sum(state_nodes, axis=0) / float(Tmax)

                    sc = plt.scatter(nodes_coords[:, 0], nodes_coords[:, 1], c=activation_freq,
                                     cmap='magma', s=3, alpha=0.6)
                    plt.colorbar(sc, label='Activation Frequency')
